INSERT INTO CONSTRAINTS (id, main_category, sub_category, detail_category, description) VALUES
(1, '外部依存リスク', '経済性', 'API価格の100倍騰貴', '利用中の外部APIが明日から突然100倍の価格に。機能を削って無料を維持するか、ユーザーに課金を強いるかの経営判断。'),
(2, 'データ管理', '機密性', 'DBの「ゼロ知識」化', '「開発者にデータを見られたくない」という要求。DBを全暗号化し、サーバー側での検索・集計機能をすべて捨てる覚悟があるか。'),
(3, 'オフライン', '整合性', '強制オフライン＆自動同期', '電波ゼロの環境で操作し、復帰時に「何事もなかったかのように」同期しろ。データ衝突（コンフリクト）をどう解消するか。'),
(4, '実行環境', 'スペック', '10年前の低スペックPC保証', '最新Macではなく、メモリ4GBの古いWindowsが標準環境。リッチなライブラリを捨てて、徹底的に軽量化できるか。'),
(5, '法規制', 'プライバシー', '「忘れられる権利」の完遂', '退会者のデータをログやバックアップからも「完全に」消去せよ。整合性を保ちつつ痕跡を消す、複雑なバッチ設計の要求。'),
(6, '運用設計', '整合性', '新旧バージョン混在（キャッシュ地獄）', 'サーバー更新直後、ブラウザを開きっぱなしのユーザーが「古いJS」で叩いてくる。APIを二重メンテするか、強制リロードさせるか。'),
(7, 'セキュリティ', '認証', '超高頻度な多要素認証（MFA）', 'セキュリティ基準により10分おきの再認証が必須に。激しく低下するUX（使い勝手）を、どんなアイデアでカバーするか。'),
(8, '権限・サンドボックス', 'OSアクセス', 'ブラウザの「鉄壁ガード」突破', '「ローカルファイルを直接上書きしたい」等の要求。ブラウザの制限を諦めるか、別途ローカルアプリを併用させる二段構えにするか。'),
(9, '事業継続', '信頼性', '24/365の「無停止」義務', '止まったら賠償金が発生する極限状態。自分の睡眠時間を削って保守するか、コストをかけてシステムを二重化（冗長化）するか。'),
(10, '仕様変更', 'ステークホルダー', '「俺専用」カスタマイズの罠', '大口顧客が「標準機能とは真逆」の変更を要求。コードを汚して目先の金を取るか、美学を貫いて製品の将来を守るか。');
INSERT INTO CONSTRAINTS (id, main_category, sub_category, detail_category, description) VALUES
(11, '【normal】ユーザー体験', 'ブラウザ挙動', '「戻る」ボタンの禁止', 'ブラウザの「戻る」ボタンで入力データが消えるとクレーム。状態管理を適切に行い、戻っても内容を保持するか警告を出せ。'),
(12, '【normal】アクセシビリティ', '視認性', 'フォントサイズの強制変更', '「文字が小さくて読めない」という高齢ユーザーの要望。レイアウトを崩さずに、OSやブラウザの拡大機能に耐えられる設計にせよ。'),
(13, '【normal】運用管理', 'コンテンツ検閲', '不適切な投稿への対策', '公序良俗に反する画像や文言が投稿された。人力管理は限界。通報機能や、特定の単語を伏せ字にするフィルタを実装せよ。'),
(14, '【normal】環境依存', '外観設定', 'ダークモード完全対応', 'OSの設定がダークモードの時に、文字が背景に溶け込んで見えなくなった。全画面を「ライト/ダーク両対応」のカラーパレットに修正せよ。'),
(15, '【normal】パフォーマンス', 'データ増大', '検索結果の「1万件表示」', '運用が長くなりデータが増えた結果、一覧画面の表示に10秒かかるようになった。ページネーションか遅延読み込みを即座に実装せよ。');
INSERT INTO CONSTRAINTS (id, main_category, sub_category, detail_category, description) VALUES
(21, '【easy】UX/UI', 'バリデーション', '空文字・異常値の投入', 'フォームに何も入れずに「送信」されたり、数字の場所に文字を入れられてエラー。適切なエラーメッセージを表示し、システムを落とさないようにせよ。'),
(22, '【easy】セキュリティ', '脆弱性', 'XSS（クロスサイトスクリプティング）', '入力フォームにJavaScript（<script>等）を書き込まれ、そのまま実行されてしまった。エスケープ処理を徹底し、攻撃を無効化せよ。'),
(23, '【easy】ネットワーク', 'UX', '二重送信の防止', '通信が遅い時にボタンを連打され、データが2重に登録された。送信中のボタン無効化（ローディング表示）を全箇所に実装せよ。'),
(24, '【easy】レスポンシブ', 'レイアウト', 'スマホ画面での表示崩れ', 'PCでは綺麗だが、スマホで見るとボタンがはみ出して押せない。メディアクエリを使い、主要なモバイル端末で操作可能にせよ。'),
(25, '【easy】認証・認可', '権限管理', 'URL直接入力による閲覧', 'ログイン後の画面URLを直接打ち込んだら、ログインしていない他人でも見えてしまった。セッションチェックを厳格に行い、不正アクセスを遮断せよ。');